import{_ as e,o as a,c as r,ag as o}from"./chunks/framework.DXGyWiRo.js";const m=JSON.parse('{"title":"Reports & Analytics","description":"","frontmatter":{},"headers":[],"relativePath":"modules/reports.md","filePath":"modules/reports.md"}'),d={name:"modules/reports.md"};function n(l,t,i,s,h,p){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="reports-analytics" tabindex="-1">Reports &amp; Analytics <a class="header-anchor" href="#reports-analytics" aria-label="Permalink to &quot;Reports &amp; Analytics&quot;">​</a></h1><p>The Reports module is GeniusHRM&#39;s unified analytics dashboard. It consolidates data from all modules into visual, filterable dashboards that help HR teams, managers, and executives make data-driven decisions about their workforce.</p><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Navigate to <strong>HR Panel → Reports</strong> or <code>/reports</code>. The module contains the following report sections:</p><table tabindex="0"><thead><tr><th>Report</th><th>URL</th><th>Data Source</th></tr></thead><tbody><tr><td><strong>Overview Dashboard</strong></td><td><code>/reports</code></td><td>All modules</td></tr><tr><td><strong>Headcount</strong></td><td><code>/reports/headcount</code></td><td>Employees</td></tr><tr><td><strong>Attendance</strong></td><td><code>/reports/attendance</code></td><td>Attendance module</td></tr><tr><td><strong>Leave</strong></td><td><code>/reports/leave</code></td><td>Leave module</td></tr><tr><td><strong>Payroll</strong></td><td><code>/reports/payroll</code></td><td>Payroll module</td></tr><tr><td><strong>Training</strong></td><td><code>/reports/training</code></td><td>Training module</td></tr><tr><td><strong>Performance</strong></td><td><code>/reports/performance</code></td><td>Performance module</td></tr></tbody></table><hr><h2 id="overview-dashboard" tabindex="-1">Overview Dashboard <a class="header-anchor" href="#overview-dashboard" aria-label="Permalink to &quot;Overview Dashboard&quot;">​</a></h2><p>The Overview Dashboard provides a high-level snapshot of the entire HR function on a single page.</p><h3 id="kpi-cards" tabindex="-1">KPI Cards <a class="header-anchor" href="#kpi-cards" aria-label="Permalink to &quot;KPI Cards&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Card</th><th>Metric</th></tr></thead><tbody><tr><td><strong>Total Employees</strong></td><td>Active headcount</td></tr><tr><td><strong>New This Month</strong></td><td>Employees hired in the current month</td></tr><tr><td><strong>On Leave Today</strong></td><td>Count of employees with active approved leave</td></tr><tr><td><strong>Pending Leave</strong></td><td>Leave requests awaiting approval</td></tr><tr><td><strong>Upcoming Birthdays</strong></td><td>Employees with birthdays in the next 7 days</td></tr><tr><td><strong>Pending Probations</strong></td><td>Employees whose probation ends within 30 days</td></tr><tr><td><strong>Open Positions</strong></td><td>Active job postings</td></tr><tr><td><strong>Upcoming Training</strong></td><td>Sessions starting in the next 7 days</td></tr></tbody></table><h3 id="charts-on-overview" tabindex="-1">Charts on Overview <a class="header-anchor" href="#charts-on-overview" aria-label="Permalink to &quot;Charts on Overview&quot;">​</a></h3><ol><li><strong>Headcount by Department</strong> — Horizontal bar chart showing employee count per department</li><li><strong>Gender Distribution</strong> — Pie chart</li><li><strong>Employment Type Mix</strong> — Donut chart (Full-time vs. Part-time vs. Contract vs. Intern)</li><li><strong>Monthly Hires vs. Exits</strong> — Line chart for the last 12 months</li><li><strong>Leave Status This Month</strong> — Stacked bar (Approved / Pending / Rejected)</li></ol><hr><h2 id="headcount-report" tabindex="-1">Headcount Report <a class="header-anchor" href="#headcount-report" aria-label="Permalink to &quot;Headcount Report&quot;">​</a></h2><p>The Headcount Report provides detailed workforce composition analytics.</p><h3 id="available-filters" tabindex="-1">Available Filters <a class="header-anchor" href="#available-filters" aria-label="Permalink to &quot;Available Filters&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Filter</th><th>Options</th></tr></thead><tbody><tr><td><strong>As of Date</strong></td><td>Snapshot on any past or current date</td></tr><tr><td><strong>Department</strong></td><td>One or all departments</td></tr><tr><td><strong>Position</strong></td><td>One or all positions</td></tr><tr><td><strong>Employment Type</strong></td><td>Full-time, Part-time, Contract, Intern</td></tr><tr><td><strong>Gender</strong></td><td>Male, Female, Other</td></tr><tr><td><strong>Status</strong></td><td>Active, On Leave, etc.</td></tr></tbody></table><h3 id="report-sections" tabindex="-1">Report Sections <a class="header-anchor" href="#report-sections" aria-label="Permalink to &quot;Report Sections&quot;">​</a></h3><h4 id="breakdown-by-department" tabindex="-1">Breakdown by Department <a class="header-anchor" href="#breakdown-by-department" aria-label="Permalink to &quot;Breakdown by Department&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Column</th><th>Description</th></tr></thead><tbody><tr><td>Department</td><td>Department name</td></tr><tr><td>Total</td><td>Total headcount</td></tr><tr><td>Male</td><td>Male employee count</td></tr><tr><td>Female</td><td>Female employee count</td></tr><tr><td>Full-time</td><td>Full-time employees</td></tr><tr><td>Part-time</td><td>Part-time employees</td></tr></tbody></table><h4 id="breakdown-by-gender" tabindex="-1">Breakdown by Gender <a class="header-anchor" href="#breakdown-by-gender" aria-label="Permalink to &quot;Breakdown by Gender&quot;">​</a></h4><p>Pie chart and table showing gender distribution.</p><h4 id="breakdown-by-contract-type" tabindex="-1">Breakdown by Contract Type <a class="header-anchor" href="#breakdown-by-contract-type" aria-label="Permalink to &quot;Breakdown by Contract Type&quot;">​</a></h4><p>Donut chart and table: Full-time / Part-time / Contract / Intern percentages.</p><h4 id="tenure-buckets" tabindex="-1">Tenure Buckets <a class="header-anchor" href="#tenure-buckets" aria-label="Permalink to &quot;Tenure Buckets&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Bucket</th><th>Description</th></tr></thead><tbody><tr><td>&lt; 1 Year</td><td>Employees hired less than 12 months ago</td></tr><tr><td>1–2 Years</td><td></td></tr><tr><td>2–5 Years</td><td></td></tr><tr><td>5–10 Years</td><td></td></tr><tr><td>10+ Years</td><td>Highly tenured employees</td></tr></tbody></table><p>Table and bar chart showing how the workforce is distributed across tenure brackets.</p><h4 id="age-distribution" tabindex="-1">Age Distribution <a class="header-anchor" href="#age-distribution" aria-label="Permalink to &quot;Age Distribution&quot;">​</a></h4><p>Employees grouped by age bracket:</p><ul><li>Under 25</li><li>25–34</li><li>35–44</li><li>45–54</li><li>55+</li></ul><hr><h2 id="attendance-report" tabindex="-1">Attendance Report <a class="header-anchor" href="#attendance-report" aria-label="Permalink to &quot;Attendance Report&quot;">​</a></h2><p>The Attendance Report provides a month-by-month view of workforce attendance patterns.</p><h3 id="month-navigator" tabindex="-1">Month Navigator <a class="header-anchor" href="#month-navigator" aria-label="Permalink to &quot;Month Navigator&quot;">​</a></h3><p>Use the <strong>Previous</strong> / <strong>Next</strong> arrows or the month/year selector to navigate between periods.</p><h3 id="summary-kpis" tabindex="-1">Summary KPIs <a class="header-anchor" href="#summary-kpis" aria-label="Permalink to &quot;Summary KPIs&quot;">​</a></h3><p>For the selected month:</p><table tabindex="0"><thead><tr><th>Metric</th><th>Description</th></tr></thead><tbody><tr><td>Total Working Days</td><td>Number of workdays in the month</td></tr><tr><td>Average Attendance Rate</td><td>% of employees present (or on approved leave) on an average day</td></tr><tr><td>Total Absent Days</td><td>Sum of all Absent records</td></tr><tr><td>Total Late Days</td><td>Sum of all Late records</td></tr><tr><td>Total Half Days</td><td>Sum of all Half Day records</td></tr></tbody></table><h3 id="stacked-bar-chart" tabindex="-1">Stacked Bar Chart <a class="header-anchor" href="#stacked-bar-chart" aria-label="Permalink to &quot;Stacked Bar Chart&quot;">​</a></h3><p>A day-by-day stacked bar chart for the selected month shows:</p><ul><li>Present (green)</li><li>Late (yellow)</li><li>Absent (red)</li><li>On Leave (purple)</li><li>Weekend/Holiday (grey)</li></ul><h3 id="employee-level-detail-table" tabindex="-1">Employee-Level Detail Table <a class="header-anchor" href="#employee-level-detail-table" aria-label="Permalink to &quot;Employee-Level Detail Table&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Description</th></tr></thead><tbody><tr><td>Employee</td><td>Name and ID</td></tr><tr><td>Department</td><td>Department</td></tr><tr><td>Present</td><td>Days present</td></tr><tr><td>Late</td><td>Days late</td></tr><tr><td>Absent</td><td>Days absent</td></tr><tr><td>Half Days</td><td>Half-day count</td></tr><tr><td>Leave Days</td><td>Approved leave days</td></tr><tr><td>Attendance %</td><td>Present+Late / Total Working Days</td></tr></tbody></table><hr><h2 id="leave-report" tabindex="-1">Leave Report <a class="header-anchor" href="#leave-report" aria-label="Permalink to &quot;Leave Report&quot;">​</a></h2><p>The Leave Report shows leave utilisation across employees, leave types, and time periods.</p><h3 id="year-filter" tabindex="-1">Year Filter <a class="header-anchor" href="#year-filter" aria-label="Permalink to &quot;Year Filter&quot;">​</a></h3><p>Select the year to view. The report always covers full financial years.</p><h3 id="leave-by-type" tabindex="-1">Leave by Type <a class="header-anchor" href="#leave-by-type" aria-label="Permalink to &quot;Leave by Type&quot;">​</a></h3><p>Pie chart and table showing:</p><ul><li>Total days requested per leave type</li><li>Days approved vs. rejected per type</li></ul><h3 id="monthly-leave-trend" tabindex="-1">Monthly Leave Trend <a class="header-anchor" href="#monthly-leave-trend" aria-label="Permalink to &quot;Monthly Leave Trend&quot;">​</a></h3><p>Line chart: total approved leave days per month over 12 months. Useful for spotting seasonal leave spikes.</p><h3 id="employee-leave-summary" tabindex="-1">Employee Leave Summary <a class="header-anchor" href="#employee-leave-summary" aria-label="Permalink to &quot;Employee Leave Summary&quot;">​</a></h3><p>For each employee in the selected year:</p><table tabindex="0"><thead><tr><th>Column</th><th>Description</th></tr></thead><tbody><tr><td>Employee</td><td>Name and department</td></tr><tr><td>Annual Leave Used</td><td>Days of annual leave taken</td></tr><tr><td>Sick Leave Used</td><td>Days of sick leave taken</td></tr><tr><td>Other Leave Used</td><td>Days of other leave types</td></tr><tr><td>Total Leave Days</td><td>Sum of all leave</td></tr><tr><td>Remaining Balance</td><td>Annual leave remaining</td></tr></tbody></table><hr><h2 id="payroll-report" tabindex="-1">Payroll Report <a class="header-anchor" href="#payroll-report" aria-label="Permalink to &quot;Payroll Report&quot;">​</a></h2><p>The Payroll Report provides a financial overview of compensation expenditure.</p><h3 id="yearly-breakdown" tabindex="-1">Yearly Breakdown <a class="header-anchor" href="#yearly-breakdown" aria-label="Permalink to &quot;Yearly Breakdown&quot;">​</a></h3><p>Monthly payroll cost chart for the selected year:</p><ul><li>Total Gross Pay</li><li>Total Deductions</li><li>Total Net Pay</li></ul><p>Each bar in the chart shows the three components stacked.</p><h3 id="department-cost-analysis" tabindex="-1">Department Cost Analysis <a class="header-anchor" href="#department-cost-analysis" aria-label="Permalink to &quot;Department Cost Analysis&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Description</th></tr></thead><tbody><tr><td>Department</td><td>Department name</td></tr><tr><td>Total Gross</td><td>Total gross payroll for the period</td></tr><tr><td>Total Deductions</td><td>Total deductions</td></tr><tr><td>Total Net</td><td>Total net payroll</td></tr><tr><td>Avg Salary</td><td>Average salary per employee</td></tr><tr><td>Employee Count</td><td>Employees in payroll runs</td></tr></tbody></table><h3 id="year-over-year-comparison" tabindex="-1">Year-over-Year Comparison <a class="header-anchor" href="#year-over-year-comparison" aria-label="Permalink to &quot;Year-over-Year Comparison&quot;">​</a></h3><p>Side-by-side bar chart comparing total payroll cost for the current year vs. previous year, month by month.</p><hr><h2 id="training-report" tabindex="-1">Training Report <a class="header-anchor" href="#training-report" aria-label="Permalink to &quot;Training Report&quot;">​</a></h2><p>See <a href="/modules/training.html#training-reports">Training &amp; Development → Training Reports</a> for the full training analytics description.</p><p>Key metrics:</p><ul><li>Completion rates by category</li><li>Monthly training activity</li><li>Department training coverage</li><li>Top courses by enrollment and completion</li></ul><hr><h2 id="performance-report" tabindex="-1">Performance Report <a class="header-anchor" href="#performance-report" aria-label="Permalink to &quot;Performance Report&quot;">​</a></h2><p>See <a href="/modules/performance.html#performance-reports">Performance Management → Performance Reports</a> for the full performance analytics description.</p><p>Key metrics:</p><ul><li>Rating distribution chart</li><li>Cycle summary table</li><li>Department comparison</li><li>Individual performance history</li></ul><hr><h2 id="exporting-reports" tabindex="-1">Exporting Reports <a class="header-anchor" href="#exporting-reports" aria-label="Permalink to &quot;Exporting Reports&quot;">​</a></h2><p>All reports support CSV export:</p><ol><li>Apply the desired filters</li><li>Click <strong>Export CSV</strong> (top right of the report)</li><li>The export includes all data in the filtered view</li></ol><p>For chart exports (PNG):</p><ol><li>Hover over any chart</li><li>Click the <strong>...</strong> menu (top right of the chart)</li><li>Select <strong>Download PNG</strong> or <strong>Download SVG</strong></li></ol>',84)])])}const y=e(d,[["render",n]]);export{m as __pageData,y as default};
